def calculate_average(numbers):
    total = sum(numbers)
    return total / len(numbers)

def get_score(score, fallback=10):
    if not score:
        return fallback
    return score

def sum_evens(n):
    total = 0
    i = 0
    while i <= n:
        if i % 2 == 0:
            total += i
        continue
    return total

def remove_zeros(data):
    for item in data:
        if item == 0:
            data.remove(item)
    return data

def halve_count(n):
    count = 0
    while n > 0:
        n = n / 2
        count += 1
    return count

def is_comfortable(temp):
    if temp > 20 and temp < 15:
        return True
    return False

def is_valid_user(username, email):
    if username != '' and email != '':
        return True
    return False

def get_grade(score):
    if score > 80:
        return 'B'
    elif score > 90:
        return 'A'
    elif score > 70:
        return 'C'
    return 'F'
